	@Test
	void semanticScopeLatticeSeparatesObserverStrengthFromRouteRequirement() {
		assertTrue(SemanticScope.BAG.isAdmissibleFor(SemanticScope.BAG));
		assertTrue(SemanticScope.BAG.isAdmissibleFor(SemanticScope.SET));
		assertTrue(SemanticScope.BAG.isAdmissibleFor(SemanticScope.EXISTENCE));
		assertFalse(SemanticScope.SET.isAdmissibleFor(SemanticScope.BAG));
		assertTrue(SemanticScope.SET.isAdmissibleFor(SemanticScope.SET));
		assertTrue(SemanticScope.SET.isAdmissibleFor(SemanticScope.EXISTENCE));
		assertFalse(SemanticScope.EXISTENCE.isAdmissibleFor(SemanticScope.BAG));
		assertFalse(SemanticScope.EXISTENCE.isAdmissibleFor(SemanticScope.SET));
		assertTrue(SemanticScope.EXISTENCE.isAdmissibleFor(SemanticScope.EXISTENCE));

		assertEquals(SemanticScope.SET, SemanticScope.BAG.constrainedBy(SemanticScope.SET));
		assertEquals(SemanticScope.EXISTENCE, SemanticScope.SET.constrainedBy(SemanticScope.EXISTENCE));
		assertEquals(SemanticScope.BAG, SemanticScope.SET.broadenedWith(SemanticScope.BAG));
		assertEquals(SemanticScope.SET, SemanticScope.EXISTENCE.broadenedWith(SemanticScope.SET));
		assertEquals(OptimizationGoal.BAG_SEMANTICS, SemanticScope.BAG.externalName());
		assertEquals(SemanticScope.SET, SemanticScope.fromExternalName(OptimizationGoal.SET_SEMANTICS));
	}

