	@Test
	void semanticEdgeRequirementsAreImmutableExpressionIdentity() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		Group aggregate = new Group(pattern("s", "p", "o"));
		aggregate.addGroupElement(new GroupElem("count", new Count(new Var("o"), true)));
		int aggregateGroupId = memo.intern(aggregate);
		MemoExpr setEdge = memo.group(aggregateGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.findFirst()
				.orElseThrow();
		RuleProof proof = new RuleProof("stronger-bag-edge", RuleKind.TRANSFORMATION,
				OptimizationGoal.BAG_SEMANTICS, Set.of("bagChildRequired"),
				"A stronger BAG child contract remains a legal implementation of this observer");

		MemoExpr bagEdge = memo.addLogicalAlternativeWithInputs(aggregateGroupId, aggregate.clone(),
				setEdge.inputGroupIds(), List.of(proof), SemanticScope.BAG, List.of(SemanticScope.BAG))
				.orElseThrow();

		assertEquals(SemanticScope.SET, setEdge.inputs().getFirst().requiredSemanticScope());
		assertEquals(SemanticScope.BAG, bagEdge.inputs().getFirst().requiredSemanticScope());
		assertNotEquals(setEdge.structuralKey(), bagEdge.structuralKey(),
				"Different parent-edge observer contracts must never merge into one memo expression");
	}

